  /// Upstream name: `CAMERA_IDLE_NO_ONE_IS_ATTEMPTING_TO_CHANGE_CAMERA_SETTINGS`
  cameraIdleNoOneIsAttemptingToChangeCameraSettings(0),
  /// Upstream name: `CAMERA_CONTROL_CAMERA_IS_IN_A_MENU_OR_CHANGING_SETTINGS_TO_INTERVENE_APP_MUST_REQUEST_CONTROL`
  cameraControlCameraIsInAMenuOrChangingSettingsToInterveneAppMustRequestControl(1),
  /// Upstream name: `CAMERA_EXTERNAL_CONTROL_AN_OUTSIDE_ENTITY_APP_HAS_CONTROL_AND_IS_IN_A_MENU_OR_MODIFYING_SETTINGS`
  cameraExternalControlAnOutsideEntityAppHasControlAndIsInAMenuOrModifyingSettings(2);

  const CameraControlId(this.value);

  /// Wire value written to / read from the camera.
  final int value;

  static final Map<int, CameraControlId> _byValue = {
    for (final v in CameraControlId.values) v.value: v,
  };

  /// Looks up a value received from the camera.
  ///
  /// Returns null for an unrecognized value rather than throwing — newer
  /// firmware can and does introduce values this table predates, and an
  /// unknown setting must not take down the connection.
  static CameraControlId? fromValue(int value) => _byValue[value];
}

/// See [Open GoPro Spec](https://gopro.github.io/OpenGoPro/ble/features/statuses.html#usb-controlled-116)
enum UsbControlled {
  /// Upstream name: `DISABLED`
  disabled(0),
  /// Upstream name: `ENABLED`
  enabled(1);

  const UsbControlled(this.value);

  /// Wire value written to / read from the camera.
  final int value;

  static final Map<int, UsbControlled> _byValue = {
    for (final v in UsbControlled.values) v.value: v,
  };

  /// Looks up a value received from the camera.
  ///
  /// Returns null for an unrecognized value rather than throwing — newer
  /// firmware can and does introduce values this table predates, and an
  /// unknown setting must not take down the connection.
  static UsbControlled? fromValue(int value) => _byValue[value];
}
